  export default "import { InputNumber } from 'antd';\nimport React, { useState } from 'react';\nimport VirtualTable, { Operate, Way } from 'react-tablex';\n\nconst InputNumberRange = ({ value, onChange }) => {\n  const [f, l] = value || [];\n\n  const onChangeHandle = (l) => {\n    onChange([f, l]);\n  };\n\n  return (\n    <div style={{ display: 'flex', width: '300px' }}>\n      <InputNumber disabled value={f} />\n      <span>~</span>\n      <InputNumber value={l} onChange={onChangeHandle} />\n    </div>\n  );\n};\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '价格区间',\n    fieldkey: 'range',\n    rules: [{ required: true, message: '必填' }],\n    custom: InputNumberRange,\n    watch: [\n      {\n        handle(value, { updateCellData, store, rowIndex }) {\n          // 获取当前field数据\n          const [, l] = store[rowIndex]?.range || [];\n          // 获取上一个field数据\n          const [, perL] = value || [];\n          updateCellData([perL && perL + 1, l]);\n        },\n        deps: ['range'],\n        way: Way.Pre,\n        immediately: true,\n      },\n    ],\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([\n    ...[\n      {\n        range: [0, 1],\n      },\n      {\n        range: [],\n      },\n    ],\n  ]);\n\n  const onChange = (value) => {\n    setDataSource(value);\n  };\n\n  return (\n    <VirtualTable\n      columns={columns}\n      value={dateSource}\n      onChange={onChange}\n      operateItems={[\n        { type: Operate.Add },\n        /**\n         * 控制第一行删除禁用\n         */\n        {\n          type: Operate.Del,\n          disabled: (cellProps) => cellProps.rowIndex === 0,\n        },\n      ]}\n    />\n  );\n};\n\nexport default Demo;\n";;
  