  export default "import VirtualTable from 'react-tablex';\nimport React, { useState } from 'react';\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '年龄(第一优先级)',\n    fieldkey: 'age',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'InputNumber',\n    sortDirections: ['ascend', 'descend'],\n    sorter: {\n      compare: (a, b) => a.age - b.age,\n      multiple: 2,\n    },\n  },\n  {\n    label: '姓名',\n    fieldkey: 'name',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'Input',\n  },\n  {\n    label: '分数(第一优先级)',\n    fieldkey: 'score',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    type: 'InputNumber',\n    sorter: {\n      compare: (a, b) => a.age - b.age,\n      multiple: 1,\n    },\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([\n    { age: 38, score: 90, name: '喜羊羊' },\n    { age: 28, score: 70, name: '沸羊羊' },\n    { age: 18, score: 80, name: '美羊羊' },\n    { age: 8, score: 100, name: '懒羊羊' },\n  ]);\n\n  const onChange = (value) => {\n    console.log('valuevalue', value);\n    setDataSource(value);\n  };\n\n  return (\n    <VirtualTable columns={columns} value={dateSource} onChange={onChange} />\n  );\n};\n\nexport default Demo;\n";;
  