  export default "/** @format */\n\nimport React, { useState } from 'react';\nimport VirtualTable from 'react-tablex';\nimport { Radio, Input } from 'antd';\n\nconst RadioGroup = Radio.Group;\n\n/**\n * 自定义组件\n * 自动接收value, onChange\n */\nconst Custom = ({ value, onChange, width }) => {\n  const { type, content } = value || {};\n\n  const onSelfChange = (params: { type?: boolean; content?: string }) => {\n    onChange({ ...value, ...params });\n  };\n\n  return (\n    <div\n      className=\"custom\"\n      style={{ display: 'flex', alignItems: 'center', height: '30px' }}\n    >\n      <RadioGroup\n        onChange={e => onSelfChange({ type: e.target.value })}\n        value={type}\n      >\n        <Radio value={true}>显示</Radio>\n        <Radio value={false}>隐藏</Radio>\n      </RadioGroup>\n      {type ? (\n        <Input\n          value={content}\n          onChange={e => onSelfChange({ content: e.target.value })}\n          style={{ width: `${width}px` }}\n        />\n      ) : null}\n    </div>\n  );\n};\n\nCustom.display = ({ value }) => {\n  return <div>{value.type && value.content ? value.content : '-'}</div>;\n};\n\nconst columns = [\n  {\n    label: '序号',\n    fieldkey: 'index',\n    width: 80,\n    custom: VirtualTable.VirtualNo,\n  },\n  {\n    label: '自定义组件',\n    fieldkey: 'custom',\n    require: true,\n    rules: [{ required: true, message: '必填' }],\n    custom: {\n      edit: Custom,\n      display: Custom.display,\n    },\n    attrs: {\n      width: 150,\n    },\n  },\n];\n\nconst Demo = () => {\n  const [dateSource, setDataSource] = useState([\n    {\n      custom: {\n        type: true,\n        content: '坚持不懈，即使进展缓慢，也要记得前进的每一步都在向目标靠近。',\n      },\n    },\n    {\n      custom: {\n        type: false,\n        content: '坚持不懈，即使进展缓慢，也要记得前进的每一步都在向目标靠近。',\n      },\n    },\n  ]);\n\n  const onChange = value => {\n    setDataSource(value);\n  };\n\n  return (\n    <VirtualTable\n      readonly\n      columns={columns}\n      value={dateSource}\n      onChange={onChange}\n    />\n  );\n};\n\nexport default Demo;\n";;
  